"use client";

import {
  createContext,
  useContext,
  useState,
  useEffect,
  type ReactNode,
} from "react";

import en from "@/locales/en.json";
import lt from "@/locales/lt.json";

export type Locale = "en" | "lt";

const messages: Record<Locale, Record<string, string>> = { en, lt };

const LANG_KEY = "salary-splitter-lang";

interface LanguageContextValue {
  locale: Locale;
  setLocale: (locale: Locale) => void;
}

const LanguageContext = createContext<LanguageContextValue>({
  locale: "en",
  setLocale: () => {},
});

export function LanguageProvider({ children }: { children: ReactNode }) {
  const [locale, setLocaleState] = useState<Locale>("en");

  useEffect(() => {
    try {
      const saved = localStorage.getItem(LANG_KEY) as Locale | null;
      if (saved && messages[saved]) {
        setLocaleState(saved);
      }
    } catch {
      // ignore
    }
  }, []);

  const setLocale = (l: Locale) => {
    setLocaleState(l);
    try {
      localStorage.setItem(LANG_KEY, l);
    } catch {
      // ignore
    }
  };

  return (
    <LanguageContext.Provider value={{ locale, setLocale }}>
      {children}
    </LanguageContext.Provider>
  );
}

export function useLanguage() {
  return useContext(LanguageContext);
}

/**
 * Simple translations hook — returns a `t` function.
 * Usage:  const t = useTranslations();
 *         t("appName")
 *         t("overBy", { pct: 5 })
 */
export function useTranslations() {
  const { locale } = useLanguage();
  const dict = messages[locale];

  return function t(key: string, vars?: Record<string, string | number>) {
    let value = dict[key] ?? key;
    if (vars) {
      for (const [k, v] of Object.entries(vars)) {
        value = value.replaceAll(`{{${k}}}`, String(v));
      }
    }
    return value;
  };
}
